class Solution {
public:
    int findNthDigit(int n) {
        long long count = 9;
        int digit = 1;
        long long start = 1;
        while (n > count * digit) {
            n -= count * digit;
            digit++;
            count *= 10;
            start *= 10;
        }
        long long num = start + (n - 1) / digit;
        return to_string(num)[(n - 1) % digit] - '0';
    }
};
```
